using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: inline DataRow for simple cases ---

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "Standard tax")]
    [DataRow(5.50, 4, 0.00, 22.00, DisplayName = "Zero tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.25, 0.00, DisplayName = "Zero quantity")]
    [DataRow(10.00, 1, 1.00, 20.00, DisplayName = "100% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for richer scenarios ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalEdgeCases =>
    [
        (0.01m, 1, 0m, 0.01m),
        (1000m, 100, 0.05m, 105_000m),
        (49.99m, 3, 0.08m, 161.9676m),
    ];

    // --- CalculateTotal: exception cases ---

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below 0")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DataRow for common percentages ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(59.99, 50.0, 29.995, DisplayName = "50% off odd price")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: exception cases ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default dollar")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(5.1, "£", "£5.10", DisplayName = "Pads to 2 decimals")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.StartsWith("$", result);
        Assert.Contains("42.00", result);
    }
}

